    if not description:
        return None

    # Look for patterns like "in City, ST" or "at address in City, ST"
    # The state is typically the last 2-letter uppercase code before punctuation
    patterns = [
        r'in [^,]+,\s*([A-Z]{2})[\.,\s]',  # "in City, ST" or "in City, ST."
        r'at [^,]+ in [^,]+,\s*([A-Z]{2})[\.,\s]',  # "at address in City, ST"
        r',\s*([A-Z]{2})\b',  # Just find any 2-letter state code
    ]

    for pattern in patterns:
        match = re.search(pattern, description)
        if match:
            return match.group(1)

    return None

# Extract state for each business and sum review counts by state
state_reviews = {}
business_states = {}

for business in businesses:
    description = business.get('description', '')
    state = extract_state(description)
    if state:
        business_id = business.get('business_id', '')
        review_count = business.get('review_count', 0)

        # Convert review_count to int if it's a string
        try:
            review_count = int(review_count)
        except (ValueError, TypeError):
            review_count = 0

        business_states[business_id] = state

        if state not in state_reviews:
            state_reviews[state] = 0
        state_reviews[state] += review_count

# Find the state with the highest total reviews
if state_reviews:
    top_state = max(state_reviews, key=state_reviews.get)
    max_reviews = state_reviews[top_state]
else:
    top_state = None
    max_reviews = 0

# Prepare result
result = {
    'top_state': top_state,
    'total_reviews_in_state': max_reviews,
    'business_count_in_state': len([b for b, s in business_states.items() if s == top_state])
